"""Refactored configuration loader (Day 13).

This module is a type-annotated, safer refactor of `legacy_config_loader.py`.

Key improvements:
- Type annotations for public functions
- More explicit error handling for file I/O and JSON parsing
- Optional strict validation mode

Meta:
  created_at: 2026-04-01T09:10:00+08:00
  author: metaclaw_agent
  status: done
"""

from __future__ import annotations

import json
import os
from dataclasses import dataclass
from typing import Any, Dict, Mapping, Optional, TypedDict


class ConfigDict(TypedDict, total=False):
    host: str
    port: int
    debug: bool
    log_level: str
    timeout: int


CONFIG_DEFAULTS: ConfigDict = {
    "host": "localhost",
    "port": 8080,
    "debug": False,
    "log_level": "INFO",
    "timeout": 30,
}


class ConfigError(Exception):
    """Base error for configuration loading/validation."""


class ConfigFileError(ConfigError):
    """Raised when the config file cannot be read."""


class ConfigParseError(ConfigError):
    """Raised when the config file contents cannot be parsed."""


class ConfigValidationError(ConfigError):
    """Raised when configuration values fail validation."""


def load_config(filepath: str, *, strict: bool = False) -> ConfigDict:
    """Load config from a JSON file and merge onto defaults.

    Behavior:
    - If `filepath` does not exist: returns defaults.
    - If file exists but cannot be read/parsed:
        - strict=False (default): returns defaults.
        - strict=True: raises ConfigFileError/ConfigParseError.
    - If validation fails:
        - strict=False: returns merged config (best-effort).
        - strict=True: raises ConfigValidationError.
    """

    if not os.path.exists(filepath):
        return CONFIG_DEFAULTS.copy()

    try:
        with open(filepath, "r", encoding="utf-8") as f:
            data = json.load(f)
    except OSError as e:
        if strict:
            raise ConfigFileError(f"Failed to read config file: {filepath}") from e
        return CONFIG_DEFAULTS.copy()
    except json.JSONDecodeError as e:
        if strict:
            raise ConfigParseError(f"Invalid JSON in config file: {filepath}") from e
        return CONFIG_DEFAULTS.copy()

    if not isinstance(data, dict):
        if strict:
            raise ConfigParseError(f"Config root must be a JSON object: {filepath}")
        return CONFIG_DEFAULTS.copy()

    config: ConfigDict = CONFIG_DEFAULTS.copy()
    # Only apply known keys; ignore unknowns to avoid surprises.
    for k, v in data.items():
        if k in CONFIG_DEFAULTS:
            config[k] = v  # type: ignore[assignment]

    try:
        validate_config(config)
    except (TypeError, ValueError) as e:
        if strict:
            raise ConfigValidationError(str(e)) from e

    return config


def get_config_value(config: Mapping[str, Any], key: str, default: Optional[Any] = None) -> Any:
    """Fetch a config value with a fallback default."""
    return config.get(key, default)


def validate_config(config: Mapping[str, Any]) -> bool:
    """Validate required keys and basic types.

    Raises:
      ValueError: missing required keys
      TypeError: wrong value types
    """
    required = ["host", "port"]
    for key in required:
        if key not in config:
            raise ValueError(f"Missing required config key: {key}")

    host = config.get("host")
    if not isinstance(host, str) or not host.strip():
        raise TypeError("Config 'host' must be a non-empty string")

    port = config.get("port")
    if not isinstance(port, int):
        raise TypeError("Config 'port' must be an integer")
    if not (1 <= port <= 65535):
        raise ValueError("Config 'port' must be between 1 and 65535")

    debug = config.get("debug")
    if debug is not None and not isinstance(debug, bool):
        raise TypeError("Config 'debug' must be a boolean")

    log_level = config.get("log_level")
    if log_level is not None and not isinstance(log_level, str):
        raise TypeError("Config 'log_level' must be a string")

    timeout = config.get("timeout")
    if timeout is not None:
        if not isinstance(timeout, int):
            raise TypeError("Config 'timeout' must be an integer")
        if timeout < 0:
            raise ValueError("Config 'timeout' must be non-negative")

    return True
